  // --- 01-http.js ---
function xhrClient() {
  return typeof GM !== "undefined" && GM.xmlHttpRequest ? GM.xmlHttpRequest : GM_xmlhttpRequest;
}

const HTTP_TIMEOUT_MS = 15_000;
const HTTP_MAX_RATE_LIMIT_RETRIES = 2;
const HTTP_DEFAULT_RETRY_DELAY_MS = 1_000;
const HTTP_MAX_RETRY_DELAY_MS = 10_000;

function parseDiscordResponse(response) {
  const text = response.responseText || "{}";
  let json;
  try {
    json = JSON.parse(text);
  } catch {
    json = { raw: text };
  }

  if (response.status >= 200 && response.status < 300) {
    return json;
  }

  const detail = json.message || json.error || text.slice(0, 200);
  const error = new Error(detail || `Request returned ${response.status}`);
  error.status = response.status;
  const retryAfterSeconds = Number(json.retry_after);
  if (response.status === 429 && Number.isFinite(retryAfterSeconds) && retryAfterSeconds >= 0) {
    error.retryAfterMs = Math.ceil(retryAfterSeconds * 1000);
  }
  throw error;
}

function boundedRetryDelay(error) {
  const requested = Number(error?.retryAfterMs);
  const delayMs = Number.isFinite(requested) && requested >= 0 ? requested : HTTP_DEFAULT_RETRY_DELAY_MS;
  return delayMs <= HTTP_MAX_RETRY_DELAY_MS ? delayMs : null;
}

async function retryRateLimitedRequest(send, maxRetries = HTTP_MAX_RATE_LIMIT_RETRIES) {
  for (let attempt = 0; ; attempt += 1) {
    try {
      return await send();
    } catch (error) {
      if (error?.status !== 429 || attempt >= maxRetries) throw error;
      const retryDelayMs = boundedRetryDelay(error);
      if (retryDelayMs === null) throw error;
      await delay(retryDelayMs);
    }
  }
}

function requestOnce(method, url, body) {
  return new Promise((resolve, reject) => {
    xhrClient()({
      method,
      url,
      timeout: HTTP_TIMEOUT_MS,
      headers: { "content-type": "application/json" },
      data: body ? JSON.stringify(body) : undefined,
      onload(response) {
        try {
          resolve(parseDiscordResponse(response));
        } catch (error) {
          reject(error);
        }
      },
      onerror() {
        reject(new Error("Could not reach Discord. Check your network and webhook URL."));
      },
      ontimeout() {
        reject(new Error("The request timed out. Check your network and try again."));
      }
    });
  });
}

function request(method, url, body) {
  return retryRateLimitedRequest(() => requestOnce(method, url, body));
}

function requestMultipartOnce(url, payloadJson, files = []) {
  return new Promise((resolve, reject) => {
    const formData = new FormData();
    formData.append("payload_json", JSON.stringify(payloadJson || {}));
    files.forEach((file, index) => {
      const blob = file.blob || new Blob([file.bytes], { type: file.contentType || "application/octet-stream" });
      formData.append(file.name || `files[${index}]`, blob, file.filename || `media_${index}`);
    });

    xhrClient()({
      method: "POST",
      url,
      timeout: HTTP_TIMEOUT_MS,
      data: formData,
      onload(response) {
        try {
          resolve(parseDiscordResponse(response));
        } catch (error) {
          reject(error);
        }
      },
      onerror() {
        reject(new Error("Could not reach Discord. Check your network and webhook URL."));
      },
      ontimeout() {
        reject(new Error("The request timed out. Check your network and try again."));
      }
    });
  });
}

function requestMultipart(url, payloadJson, files = []) {
  return retryRateLimitedRequest(() => requestMultipartOnce(url, payloadJson, files));
}

function delay(ms) {
  return new Promise((resolve) => window.setTimeout(resolve, ms));
}

  // --- 02-utils.js ---
function truncate(value, limit) {
  const textValue = String(value || "").trim();
  if (textValue.length <= limit) return textValue;
  const suffix = "...";
  if (limit <= suffix.length) return suffix.slice(0, Math.max(0, limit));
  return `${textValue.slice(0, limit - suffix.length).trimEnd()}${suffix}`;
}

function unique(values) {
  return [...new Set(values.filter(Boolean))];
}

function text(node, selector) {
  return node.querySelector(selector)?.textContent?.trim() || "";
}

function absoluteUrl(url) {
  try {
    return new URL(url, location.href).toString();
  } catch {
    return "";
  }
}

function normalizeTweetUrl(url) {
  const parsed = new URL(url, location.href);
  parsed.hostname = "x.com";
  parsed.search = "";
  parsed.hash = "";
  parsed.pathname = parsed.pathname.replace(/(\/status\/\d+).*/, "$1");
  return parsed.toString();
}

function tweetIdFromUrl(url) {
  return String(url || "").match(/\/status\/(\d+)/)?.[1] || "";
}

function highResolutionProfileImageUrl(url) {
  return (url || "").replace(/_normal(\.(?:jpg|jpeg|png|webp))(?:\?|$)/i, "$1");
}

function isTweetImageMediaUrl(url) {
  const value = String(url || "");
  return /^https:\/\/pbs\.twimg\.com\/media\//i.test(value)
    && !/(?:\.svg(?:[?:]|$)|[?&]format=svg\b|:svg(?:\?|$))/i.test(value);
}

function highResolutionTweetImageUrl(url) {
  if (!isTweetImageMediaUrl(url)) return url;
  const base = url.split("?")[0].replace(/:(?:small|medium|large|orig|thumb)$/i, "");
  return `${base}?format=jpg&name=orig`;
}

function discordEmbedTimestamp(createdAt) {
  const raw = String(createdAt || "").trim();
  if (!raw) return undefined;
  const date = new Date(raw);
  return Number.isNaN(date.getTime()) ? undefined : date.toISOString();
}

function normalizeTextForMatch(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function isPlayableTweetVideoUrl(url) {
  return /^https:\/\/video\.twimg\.com\/.+\.mp4(?:\?|$)/.test(url || "") && !/\/aud\//.test(url || "");
}

function normalizeTweetVideoUrl(url) {
  if (!url) return "";
  return url.replace(/\/vid\/([^/]+)\/0\/0\/(\d+x\d+)\//, "/vid/$1/$2/");
}

function isTweetVideoPosterUrl(url) {
  return /^https:\/\/pbs\.twimg\.com\/.+\.(?:jpg|jpeg|png|webp)(?:\?|$)/.test(url || "");
}

function isTweetVideoThumbnailUrl(url) {
  return /^https:\/\/pbs\.twimg\.com\/(?:amplify_video_thumb|ext_tw_video_thumb|tweet_video_thumb)\//.test(url || "");
}

function posterMediaId(url) {
  return (url || "").match(/\/(?:amplify_video_thumb|ext_tw_video_thumb|tweet_video_thumb)\/(\d+)\//)?.[1] || "";
}

function videoQualityScore(url) {
  if (/\/amplify_video\/|\/ext_tw_video\//.test(url)) return 2_000_000_000;
  if (/\/vid\//.test(url)) return 1_000_000_000;
  if (/\/tweet_video\//.test(url)) return 500_000_000;

  const resolution = url.match(/\/(\d+)x(\d+)\//);
  if (resolution) {
    return Number(resolution[1]) * Number(resolution[2]);
  }

  const bitrate = url.match(/[?&](?:bitrate|br)=(\d+)/i) || url.match(/_(\d+)\.mp4(?:\?|$)/i);
  return bitrate ? Number(bitrate[1]) : 0;
}

function compareTweetVideoQuality(left, right) {
  return videoQualityScore(right) - videoQualityScore(left);
}

function playableVideoVariants(variants = []) {
  return variants
    .map((variant) => ({
      url: normalizeTweetVideoUrl(variant.url || variant.src || ""),
      bitrate: variant.bitrate || 0,
      type: variant.content_type || variant.type || ""
    }))
    .filter((variant) => variant.type === "video/mp4" && isPlayableTweetVideoUrl(variant.url))
    .sort((left, right) => (right.bitrate || videoQualityScore(right.url)) - (left.bitrate || videoQualityScore(left.url)));
}

function bestPlayableVideoVariantUrl(variants = []) {
  return playableVideoVariants(variants)[0]?.url || "";
}

function uniqueMedia(items) {
  return items.filter((item, index, all) => {
    const key = item.url || item.posterUrl;
    return key && all.findIndex((candidate) => (candidate.url || candidate.posterUrl) === key) === index;
  });
}

function tweetImageMediaKey(url) {
  return (url || "").match(/pbs\.twimg\.com\/media\/([^.?/:]+)/)?.[1] || "";
}

function mergeAuthor(primary = {}, fallback = {}) {
  return {
    displayName: primary.displayName || fallback.displayName || "",
    username: primary.username || fallback.username || "",
    avatarUrl: primary.avatarUrl || fallback.avatarUrl || ""
  };
}

function isInsideExcludedNode(node, excludedNodes = []) {
  return excludedNodes.some((excludedNode) => excludedNode && excludedNode !== node && excludedNode.contains(node));
}

  // --- 03-network-capture.js ---
function cacheVideoVariants(mediaId, variants) {
  if (!mediaId || !Array.isArray(variants)) return;
  const mp4s = playableVideoVariants(variants);

  if (mp4s.length > 0) {
    VIDEO_VARIANT_CACHE.set(mediaId, mp4s);
    trimCache(VIDEO_VARIANT_CACHE);
  }
}

function looksLikeTweetResult(node) {
  const legacy = node.legacy || node;
  const media = legacy.extended_entities?.media || legacy.entities?.media || [];
  const userId = legacy.user_id_str || legacy.user_id || node.user_id_str || "";
  return Boolean(
    (node.rest_id || node.id_str) &&
    (legacy.full_text || legacy.text || node.text || media.length > 0) &&
    (node.core?.user_results?.result || node.user || node.author || userId)
  );
}

function looksLikeUserResult(node) {
  return Boolean((node.rest_id || node.id_str) && (node.legacy?.screen_name || node.screen_name || node.username));
}

function cacheUserResult(node) {
  const legacy = node.legacy || node;
  const id = String(node.rest_id || node.id_str || legacy.id_str || "");
  const user = {
    displayName: legacy.name || "",
    username: legacy.screen_name || legacy.username || "",
    avatarUrl: highResolutionProfileImageUrl(legacy.profile_image_url_https || legacy.profile_image_url || "")
  };

  if (id) {
    USER_CACHE.set(id, user);
    trimCache(USER_CACHE);
  }
  if (user.username) {
    USER_CACHE.set(user.username, user);
    trimCache(USER_CACHE);
  }
}

function mediaFromLegacyTweet(legacy) {
  const media = legacy.extended_entities?.media || legacy.entities?.media || [];
  return uniqueMedia(media.flatMap((item) => {
    if (item.type === "photo") {
      return [{ type: "image", url: item.media_url_https || item.media_url || "", alt: item.ext_alt_text || "" }];
    }

    if (item.video_info?.variants) {
      const bestVideoUrl = bestPlayableVideoVariantUrl(item.video_info.variants);

      return [{
        type: "video",
        url: bestVideoUrl || "",
        posterUrl: item.media_url_https || item.media_url || "",
        alt: item.ext_alt_text || ""
      }];
    }

    return [];
  }));
}

function cacheTweetResult(node) {
  const legacy = node.legacy || node;
  const userResult = node.core?.user_results?.result;
  const userId = legacy.user_id_str || legacy.user_id || node.user_id_str || "";
  const cachedUser = userId ? USER_CACHE.get(String(userId)) : null;
  const userLegacy = userResult?.legacy || node.user || node.author || cachedUser || {};
  const username = userLegacy.screen_name || userLegacy.username || "";
  const id = String(node.rest_id || node.id_str || legacy.id_str || "");
  if (!id) return;

  TWEET_CACHE.set(id, {
    url: username ? `https://x.com/${username}/status/${id}` : `https://x.com/i/status/${id}`,
    author: {
      displayName: userLegacy.name || "",
      username,
      avatarUrl: highResolutionProfileImageUrl(userLegacy.profile_image_url_https || userLegacy.profile_image_url || "")
    },
    text: legacy.full_text || legacy.text || node.text || "",
    media: mediaFromLegacyTweet(legacy),
    createdAt: legacy.created_at || ""
  });
  trimCache(TWEET_CACHE);
}

function scanForVideoVariants(value) {
  const seen = new WeakSet();

  function visit(node) {
    if (!node || typeof node !== "object") return;
    if (seen.has(node)) return;
    seen.add(node);

    const mediaId = node.id_str || node.media_key || node.id;
    if (looksLikeTweetResult(node)) {
      cacheTweetResult(node);
    }
    if (looksLikeUserResult(node)) {
      cacheUserResult(node);
    }
    if (node.video_info?.variants) {
      cacheVideoVariants(String(mediaId || ""), node.video_info.variants);
    }
    if (node.video?.variants && node.video?.poster) {
      cacheVideoVariants(posterMediaId(node.video.poster) || String(mediaId || ""), node.video.variants);
    }
    if (node.media_url_https && node.video_info?.variants) {
      cacheVideoVariants(posterMediaId(node.media_url_https) || String(mediaId || ""), node.video_info.variants);
    }

    if (Array.isArray(node)) {
      node.forEach(visit);
      return;
    }

    Object.values(node).forEach(visit);
  }

  visit(value);
}

function shouldCaptureApiUrl(url) {
  return /\/graphql\/|\/i\/api\/graphql\/|TweetDetail|UserTweets|HomeTimeline|SearchTimeline/i.test(url);
}

function installNetworkCapture() {
  const originalFetch = window.fetch;
  if (typeof originalFetch === "function") {
    window.fetch = async function (...args) {
      const response = await originalFetch.apply(this, args);
      const url = String(args[0]?.url || args[0] || "");
      if (shouldCaptureApiUrl(url)) {
        response.clone().json().then(scanForVideoVariants).catch(() => {});
      }
      return response;
    };
  }

  const originalOpen = XMLHttpRequest.prototype.open;
  const originalSend = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function (method, url, ...rest) {
    this.__tdsUrl = String(url || "");
    return originalOpen.call(this, method, url, ...rest);
  };
  XMLHttpRequest.prototype.send = function (...args) {
    this.addEventListener("load", () => {
      if (!shouldCaptureApiUrl(this.__tdsUrl || "")) return;
      try {
        scanForVideoVariants(JSON.parse(this.responseText));
      } catch {}
    });
    return originalSend.apply(this, args);
  };
}

  // --- 04-video.js ---
function directVideoUrlsFromDocument() {
  let entries = [];
  try {
    entries = performance.getEntriesByType("resource").map((entry) => entry.name);
  } catch {
    entries = [];
  }

  const sourceUrls = [...document.querySelectorAll("video source[src], video[src]")]
    .map((node) => node.src || node.getAttribute("src") || "");

  return unique([...entries, ...sourceUrls].map(normalizeTweetVideoUrl).filter(isPlayableTweetVideoUrl))
    .sort(compareTweetVideoQuality);
}

function nearestPlayableVideoUrl(video) {
  const candidates = [
    video.currentSrc,
    video.src,
    ...[...video.querySelectorAll("source[src]")].map((source) => source.src || source.getAttribute("src") || "")
  ].map(normalizeTweetVideoUrl).filter(isPlayableTweetVideoUrl).sort(compareTweetVideoQuality);
  if (candidates.length > 0) return candidates[0];

  const poster = video.poster || "";
  const mediaId = posterMediaId(poster);
  const cached = VIDEO_VARIANT_CACHE.get(mediaId);
  if (cached?.length) return cached[0].url;

  const loadedVideos = directVideoUrlsFromDocument();
  const matchingMediaId = mediaId ? loadedVideos.filter((url) => url.includes(`/${mediaId}/`)) : [];
  if (matchingMediaId.length > 0) return matchingMediaId[0];

  const posterName = poster.split("/").pop()?.split("?")[0]?.replace(/\.(jpg|jpeg|png|webp)$/i, "") || "";
  const matchingPoster = loadedVideos.find((url) => posterName && url.includes(posterName));
  if (matchingPoster) return matchingPoster;

  return "";
}

function imageMedia(tweet) {
  return (tweet.media || []).filter((item) => item.type === "image" && item.url && !isTweetVideoThumbnailUrl(item.url));
}

function videoMedia(tweet) {
  return (tweet.media || []).filter((item) => item.type === "video" && (item.url || item.posterUrl));
}

function directPlayableVideoUrls(tweet) {
  return unique(videoMedia(tweet).map((item) => normalizeTweetVideoUrl(item.url)).filter(isPlayableTweetVideoUrl));
}

function bestCachedVideoUrlForTweet(tweet) {
  const mediaIds = videoMedia(tweet).map((item) => posterMediaId(item.posterUrl)).filter(Boolean);
  for (const mediaId of mediaIds) {
    const cached = VIDEO_VARIANT_CACHE.get(mediaId);
    if (cached?.length) return cached[0].url;
  }
  return "";
}

  // --- 05-format-discord.js ---
function formatAuthor(tweet) {
  const author = tweet.author?.displayName || tweet.author?.username || "Unknown author";
  const username = tweet.author?.username ? `@${tweet.author.username}` : "";
  return [author, username].filter(Boolean).join(" ");
}

function tweetAuthorAvatarUrl(tweet) {
  const url = highResolutionProfileImageUrl(tweet.author?.avatarUrl);
  return isHttpsUrl(url) ? url : undefined;
}

function webhookSenderName() {
  return WEBHOOK_SENDER_NAME;
}

function embedAuthorDisplayName(tweet) {
  const displayName = String(tweet.author?.displayName || "").trim();
  const username = String(tweet.author?.username || "").trim();
  if (displayName) return truncate(displayName, DISCORD_EMBED_LIMITS.authorName);
  if (username) return truncate(`@${username}`, DISCORD_EMBED_LIMITS.authorName);
  return "Unknown author";
}

function webhookSenderAvatarUrl() {
  return WEBHOOK_SENDER_AVATAR_URL;
}

function uniqueMediaLinks(items) {
  return items.filter((item, index, all) => {
    if (!item.url) return false;
    const key = item.kind === "image" ? (tweetImageMediaKey(item.url) || item.url) : item.url;
    return all.findIndex((candidate) => {
      const candidateKey = candidate.kind === "image" ? (tweetImageMediaKey(candidate.url) || candidate.url) : candidate.url;
      return candidateKey === key;
    }) === index;
  });
}

function tweetHasEmbedImageMedia(tweet) {
  return imageMedia(tweet).length > 0;
}

function needsMediaPostPrefix(rootTweet, shareOptions = {}) {
  const { includeQuote = true } = shareOptions;
  if (!includeQuote || !hasQuoteTweet(rootTweet)) return false;
  return tweetHasEmbedImageMedia(rootTweet) && tweetHasEmbedImageMedia(rootTweet.quote);
}

function resolveQuoteLayout(tweet, shareOptions = {}) {
  const mode = shareOptions.quoteLayout || "auto";
  if (shareOptions.includeQuote === false || !hasQuoteTweet(tweet)) return "none";
  if (mode === "card") return "card";
  if (mode === "inline") return "inline";
  return "inline";
}

function mediaCaption(kind, postTweet, index, shareOptions = {}, rootTweet = postTweet) {
  const label = kind === "video" ? `Video ${index + 1}` : `Image ${index + 1}`;
  if (!needsMediaPostPrefix(rootTweet, shareOptions)) return label;
  return `${embedAuthorDisplayName(postTweet)} · ${label}`;
}

function videoCaption(postTweet, index, shareOptions = {}, rootTweet = postTweet) {
  const includeQuote = shareOptions.includeQuote !== false;
  const label = `Video ${index + 1}`;
  if (!includeQuote || !hasQuoteTweet(rootTweet)) return label;
  const bothPostsHaveVideo = directPlayableVideoUrls(rootTweet).length > 0 && directPlayableVideoUrls(rootTweet.quote).length > 0;
  return bothPostsHaveVideo || needsMediaPostPrefix(rootTweet, shareOptions) ? `${embedAuthorDisplayName(postTweet)} · ${label}` : label;
}

function mediaLinks(tweet, shareOptions = {}) {
  const rootTweet = shareOptions.rootTweet || tweet;
  const videos = directPlayableVideoUrls(tweet).map((url, index) => ({
    kind: "video",
    label: videoCaption(tweet, index, shareOptions, rootTweet),
    url
  }));
  const images = imageMedia(tweet).map((item, index) => ({
    kind: "image",
    label: mediaCaption("image", tweet, index, shareOptions, rootTweet),
    url: item.url
  }));

  return uniqueMediaLinks([...videos, ...images]);
}

function collectMediaAttachmentUrls(tweet, shareOptions = {}) {
  const { includeQuote = true } = shareOptions;
  const posts = [tweet];
  if (includeQuote && hasQuoteTweet(tweet)) posts.push(tweet.quote);
  const urls = [];

  for (const post of posts) {
    for (const item of post.media || []) {
      if (item.type === "video") {
        const url = normalizeTweetVideoUrl(item.url);
        if (isPlayableTweetVideoUrl(url)) urls.push(url);
      } else if (item.type === "image" && isTweetImageMediaUrl(item.url) && !isTweetVideoThumbnailUrl(item.url)) {
        urls.push(item.url);
      }
    }
  }

  return unique(urls);
}

function isHttpsUrl(url) {
  return /^https:\/\//i.test(String(url || ""));
}

function isValidEmbedImageUrl(url) {
  try {
    const parsed = new URL(url);
    return parsed.protocol === "https:" && parsed.hostname === "pbs.twimg.com";
  } catch {
    return false;
  }
}

function embedAuthorBlock(tweet) {
  const block = { name: embedAuthorDisplayName(tweet) };
  const iconUrl = tweetAuthorAvatarUrl(tweet);
  if (isHttpsUrl(iconUrl)) block.icon_url = iconUrl;
  if (tweet.author?.username) block.url = `https://x.com/${tweet.author.username}`;
  return block;
}

function tweetSourceLabel(tweet, kind = "main") {
  const parts = [];
  if (kind === "quote") parts.push("Quoted post");

  const url = String(tweet.url || "").trim();
  const hostMatch = /^https?:\/\/([^/]+)/i.exec(url);
  if (hostMatch) parts.push(hostMatch[1].replace(/^www\./, ""));

  return parts.length ? parts.join(" · ") : "x.com";
}

function embedFooterForTweet(tweet, kind = "main") {
  return { text: truncate(tweetSourceLabel(tweet, kind), DISCORD_EMBED_LIMITS.footer) };
}

function countEmbedChars(embed) {
  let total = 0;
  if (embed.title) total += embed.title.length;
  if (embed.description) total += embed.description.length;
  if (embed.footer?.text) total += embed.footer.text.length;
  if (embed.author?.name) total += embed.author.name.length;
  for (const field of embed.fields || []) {
    total += (field.name || "").length + (field.value || "").length;
  }
  return total;
}

function rebalanceEmbedFields(embed, maxChars = DISCORD_EMBED_LIMITS.totalEmbedChars) {
  if (countEmbedChars(embed) <= maxChars) return [embed];

  const fields = [...(embed.fields || [])];
  if (!fields.length) return [embed];

  const base = { ...embed };
  delete base.fields;
  const kept = [];
  const spilled = [];

  for (const field of fields) {
    const trial = pruneEmbed({ ...base, fields: [...kept, field] });
    if (countEmbedChars(trial) <= maxChars) {
      kept.push(field);
    } else {
      spilled.push(field);
    }
  }

  const primary = pruneEmbed(kept.length ? { ...embed, fields: kept } : base);
  if (!spilled.length) return [primary];

  const spillEmbeds = [];
  let batch = [];
  for (const field of spilled) {
    const trial = pruneEmbed({ color: embed.color, fields: [...batch, field] });
    if (countEmbedChars(trial) <= maxChars || !batch.length) {
      batch.push(field);
    } else {
      spillEmbeds.push(pruneEmbed({ color: embed.color, fields: batch }));
      batch = [field];
    }
  }
  if (batch.length) spillEmbeds.push(pruneEmbed({ color: embed.color, fields: batch }));

  const parts = [primary, ...spillEmbeds].filter((part) => countEmbedChars(part) > 0);
  return parts.map((part, index) => {
    if (index === 0) return part;
    return pruneEmbed({
      ...part,
      title: truncate(`Continued (${index + 1}/${parts.length})`, DISCORD_EMBED_LIMITS.title)
    });
  });
}

function rebalanceEmbedsForCharBudget(embeds, maxChars = DISCORD_EMBED_LIMITS.totalEmbedChars) {
  return embeds.flatMap((embed) => rebalanceEmbedFields(embed, maxChars));
}

function pruneEmbed(embed) {
  const next = { ...embed };
  for (const key of Object.keys(next)) {
    if (next[key] === undefined || next[key] === null || next[key] === "") delete next[key];
  }
  if (next.fields?.length === 0) delete next.fields;
  return next;
}

function formatQuoteFieldValue(text) {
  const trimmed = String(text || "").trim();
  if (!trimmed) return "";
  return truncate(trimmed.split("\n").map((line) => `> ${line}`).join("\n"), DISCORD_EMBED_LIMITS.fieldValue);
}

function permalinkField(name, url) {
  if (!url) return null;
  return {
    name: truncate(name, DISCORD_EMBED_LIMITS.fieldName),
    value: truncate(url, DISCORD_EMBED_LIMITS.fieldValue),
    inline: false
  };
}

function buildInlineQuoteFields(tweet) {
  const quote = tweet.quote;
  if (!quote) return [];

  const username = quote.author?.username ? `@${quote.author.username}` : "unknown";
  const fields = [];
  const quoteBody = formatQuoteFieldValue(quote.text);
  if (quoteBody) {
    fields.push({
      name: truncate(`Quoted post from ${username}`, DISCORD_EMBED_LIMITS.fieldName),
      value: quoteBody,
      inline: false
    });
  }
  const originalField = permalinkField("Original post", tweet.url);
  if (originalField) fields.push(originalField);
  return fields;
}

function buildShareContentLines(tweet, shareOptions = {}) {
  const lines = [];
  if (tweet.url) lines.push(tweet.url);
  if (resolveQuoteLayout(tweet, shareOptions) !== "none" && tweet.quote?.url) {
    lines.push(`↳ 📑 Quoted post: ${tweet.quote.url}`);
  }
  return lines.length ? truncate(lines.join("\n"), DISCORD_LIMITS.content) : undefined;
}

function pickEmbedImageUrl(mediaItems) {
  const image = mediaItems.find((item) => isValidEmbedImageUrl(item.url));
  return image?.url || "";
}

function pickEmbedHeroUrl(mediaItems) {
  return pickEmbedImageUrl(mediaItems);
}

function buildMediaHintField(imageSupplementCount) {
  if (imageSupplementCount <= 0) return null;

  const text = imageSupplementCount === 1 ? "1 more image below" : `${imageSupplementCount} more images below`;

  return {
    name: "More images",
    value: truncate(`${text} ↓`, DISCORD_EMBED_LIMITS.fieldValue),
    inline: false
  };
}

function appendMediaHintToLastContentEmbed(embeds, imageSupplementCount) {
  const hintField = buildMediaHintField(imageSupplementCount);
  if (!hintField || !embeds.length) return embeds;

  const lastContentEmbed = [...embeds].reverse().find((embed) => embed.author || embed.description);
  if (!lastContentEmbed) return embeds;

  lastContentEmbed.fields = [...(lastContentEmbed.fields || []), hintField];
  return embeds;
}

function buildImageSupplementEmbeds(tweet, mediaItems, heroUrl, kind, shareOptions = {}) {
  const color = kind === "quote" ? EMBED_COLOR_QUOTE : EMBED_COLOR_MAIN;
  const permalink = tweet.url || "";
  const attachmentUrls = shareOptions.attachmentUrls || [];

  return mediaItems
    .filter((item) =>
      item.kind === "image"
      && item.url
      && item.url !== heroUrl
      && !attachmentUrls.includes(item.url)
      && isValidEmbedImageUrl(item.url)
    )
    .map((item) =>
      pruneEmbed({
        color,
        title: truncate(item.label, DISCORD_EMBED_LIMITS.title),
        url: permalink || undefined,
        image: { url: item.url }
      })
    );
}

function assembleTweetEmbedGroup(tweet, kind, shareOptions, contentEmbeds, media, heroImageUrl) {
  const supplements = buildImageSupplementEmbeds(tweet, media, heroImageUrl, kind, shareOptions);
  const withHints = appendMediaHintToLastContentEmbed(contentEmbeds, supplements.length);
  return [...withHints, ...supplements];
}

function buildTweetEmbedGroup(tweet, kind, shareOptions = {}) {
  const color = kind === "quote" ? EMBED_COLOR_QUOTE : EMBED_COLOR_MAIN;
  const permalink = tweet.url || "";
  const text = String(tweet.text || "").trim();
  const inlineQuote = kind === "main" && shareOptions.quoteLayout === "inline" ? shareOptions.rootTweet?.quote : null;
  const inlineQuoteMedia = inlineQuote ? mediaLinks(inlineQuote, shareOptions).filter((item) => item.kind === "image") : [];
  const media = uniqueMediaLinks([...mediaLinks(tweet, shareOptions), ...inlineQuoteMedia]);
  const attachmentUrls = shareOptions.attachmentUrls || [];
  const visibleMedia = media.filter((item) => !attachmentUrls.includes(item.url));
  const visibleInlineQuoteMedia = inlineQuoteMedia.filter((item) => !attachmentUrls.includes(item.url));
  const heroImageUrl = pickEmbedHeroUrl(visibleMedia)
    || (inlineQuote ? pickEmbedHeroUrl(visibleInlineQuoteMedia) : "");
  const mediaFields = [];
  const inlineQuoteFields = kind === "main" ? (shareOptions.inlineQuoteFields || []) : [];
  const permalinkFields = kind === "quote" ? [permalinkField("Quoted post", permalink)].filter(Boolean) : [];
  const footer = embedFooterForTweet(tweet, kind);
  const descriptionChunks = splitText(text, DISCORD_EMBED_LIMITS.description);
  const contentEmbeds = [];

  if (descriptionChunks.length === 0) {
    contentEmbeds.push(
      pruneEmbed({
        color,
        author: embedAuthorBlock(tweet),
        description: media.length ? undefined : "(No text found)",
        url: permalink || undefined,
        image: heroImageUrl ? { url: heroImageUrl } : undefined,
        fields: [...mediaFields, ...inlineQuoteFields, ...permalinkFields].length ? [...mediaFields, ...inlineQuoteFields, ...permalinkFields] : undefined,
        timestamp: kind === "main" ? discordEmbedTimestamp(tweet.createdAt) : undefined,
        footer
      })
    );
    return assembleTweetEmbedGroup(
      tweet,
      kind,
      shareOptions,
      rebalanceEmbedsForCharBudget(contentEmbeds),
      media,
      heroImageUrl
    );
  }

  descriptionChunks.forEach((chunk, index) => {
    const isFirst = index === 0;
    const isLast = index === descriptionChunks.length - 1;
    contentEmbeds.push(
      pruneEmbed({
        color,
        author: isFirst ? embedAuthorBlock(tweet) : undefined,
        title:
          descriptionChunks.length > 1 && !isFirst
            ? truncate(`Continued (${index + 1}/${descriptionChunks.length})`, DISCORD_EMBED_LIMITS.title)
            : undefined,
        description: chunk,
        url: isFirst && permalink ? permalink : undefined,
        image: isFirst && heroImageUrl ? { url: heroImageUrl } : undefined,
        fields: isLast && [...mediaFields, ...inlineQuoteFields, ...permalinkFields].length ? [...mediaFields, ...inlineQuoteFields, ...permalinkFields] : undefined,
        timestamp: kind === "main" && isFirst ? discordEmbedTimestamp(tweet.createdAt) : undefined,
        footer: isLast ? footer : undefined
      })
    );
  });

  return assembleTweetEmbedGroup(
    tweet,
    kind,
    shareOptions,
    rebalanceEmbedsForCharBudget(contentEmbeds),
    media,
    heroImageUrl
  );
}

function packEmbedsIntoMessages(embeds) {
  const messages = [];
  let current = [];
  let currentChars = 0;

  for (const embed of embeds) {
    const embedChars = countEmbedChars(embed);
    const exceedsCount = current.length > 0 && currentChars + embedChars > DISCORD_EMBED_LIMITS.totalEmbedChars;
    const exceedsSlots = current.length >= DISCORD_EMBED_LIMITS.embedsPerMessage;

    if (exceedsCount || exceedsSlots) {
      messages.push(current);
      current = [];
      currentChars = 0;
    }

    current.push(embed);
    currentChars += embedChars;
  }

  if (current.length) messages.push(current);
  return messages;
}

function collectShareVideoEntries(tweet, shareOptions = {}) {
  const { includeQuote = true } = shareOptions;
  const entries = [];

  directPlayableVideoUrls(tweet).forEach((url, index) => {
    entries.push({
      url,
      caption: videoCaption(tweet, index, shareOptions, tweet)
    });
  });

  if (includeQuote && hasQuoteTweet(tweet)) {
    directPlayableVideoUrls(tweet.quote).forEach((url, index) => {
      entries.push({
        url,
        caption: videoCaption(tweet.quote, index, shareOptions, tweet)
      });
    });
  }

  return entries;
}

function buildWebhookPayload(embeds, tweet, options = {}) {
  const payload = {
    username: webhookSenderName(),
    avatar_url: webhookSenderAvatarUrl(),
    allowed_mentions: { parse: [] }
  };
  if (embeds.length) payload.embeds = embeds;
  if (options.content) payload.content = options.content;
  if (options.messageLabel) payload._messageLabel = options.messageLabel;
  return payload;
}

function buildVideoFollowUpContent(entries) {
  if (!entries.length) return undefined;
  if (entries.length === 1) return truncate(`_Video:_\n${entries[0].url}`, DISCORD_LIMITS.content);

  const blocks = entries.map((entry) => `_${entry.caption}:_\n${entry.url}`);
  return truncate(blocks.join("\n\n"), DISCORD_LIMITS.content);
}

function buildEmbedDiscordPayloads(tweet, options = {}) {
  const { includeQuote = true } = options;
  const allVideoEntries = collectShareVideoEntries(tweet, options);
  const attachmentUrls = options.attachmentUrls || [];
  const fallbackVideoUrls = Array.isArray(options.fallbackVideoUrls)
    ? options.fallbackVideoUrls
    : (options.attachMedia === true
      ? allVideoEntries.filter((entry) => !attachmentUrls.includes(entry.url)).map((entry) => entry.url)
      : allVideoEntries.map((entry) => entry.url));
  const fallbackVideoUrlSet = new Set(fallbackVideoUrls);
  const videoEntries = allVideoEntries.filter((entry) => fallbackVideoUrlSet.has(entry.url));
  const quoteLayout = resolveQuoteLayout(tweet, options);
  const shareOptions = {
    ...options,
    attachmentUrls,
    quoteLayout,
    inlineQuoteFields: quoteLayout === "inline" ? buildInlineQuoteFields(tweet) : [],
    rootTweet: tweet
  };
  const embeds = [...buildTweetEmbedGroup(tweet, "main", shareOptions)];

  if (includeQuote && hasQuoteTweet(tweet) && quoteLayout === "card") {
    embeds.push(...buildTweetEmbedGroup(tweet.quote, "quote", shareOptions));
  }

  const packed = packEmbedsIntoMessages(embeds);
  if (!packed.length) return [];

  const messages = packed.map((group, index) =>
    buildWebhookPayload(group, tweet, {
      content: index === 0 ? buildShareContentLines(tweet, shareOptions) : undefined,
      messageLabel: packed.length > 1 ? `Tweet embeds ${index + 1}/${packed.length}` : undefined
    })
  );

  const videoContent = buildVideoFollowUpContent(videoEntries);
  if (videoContent) {
    // Discord unfurls MP4 links in content, but not when custom embeds are on the same message.
    messages.push(
      buildWebhookPayload([], tweet, {
        content: videoContent,
        messageLabel: "Videos"
      })
    );
  }
  return messages;
}

function formatMediaLinkPlain(item) {
  if (MEDIA_LINK_STYLE === "masked") {
    return `[${item.label}](${item.url})`;
  }

  return `${item.label}: ${item.url}`;
}

function buildCompactPlainBody(tweet, options = {}) {
  const { includeQuote = true } = options;
  const lines = [formatAuthor(tweet)];

  if (tweet.text) lines.push(tweet.text);
  for (const item of mediaLinks(tweet)) lines.push(formatMediaLinkPlain(item));
  if (tweet.url) lines.push(tweet.url);

  if (includeQuote && hasQuoteTweet(tweet)) {
    lines.push("");
    lines.push(`↳ ${formatAuthor(tweet.quote)}`);
    if (tweet.quote.text) lines.push(tweet.quote.text);
    for (const item of mediaLinks(tweet.quote)) lines.push(formatMediaLinkPlain(item));
    if (tweet.quote.url) lines.push(tweet.quote.url);
  }

  return lines.filter((line, index, all) => line !== "" || (index > 0 && all[index - 1] !== "")).join("\n");
}

function buildPlainFallbackPayloads(tweet, options = {}) {
  const body = buildCompactPlainBody(tweet, options);
  const chunks = splitText(body, MESSAGE_CHUNK_LIMIT);
  const parts = chunks.length ? chunks : [body || formatAuthor(tweet)];

  return parts.map((content) => ({
    username: webhookSenderName(),
    avatar_url: webhookSenderAvatarUrl(),
    content: truncate(content, DISCORD_LIMITS.content),
    allowed_mentions: { parse: [] }
  }));
}

function hasQuoteCandidate(tweet) {
  if (!tweet?.quote?.url) return false;
  return tweetIdFromUrl(tweet.quote.url) && tweetIdFromUrl(tweet.quote.url) !== tweetIdFromUrl(tweet.url);
}

function hasQuoteTweet(tweet) {
  if (!tweet?.quote) return false;
  const quote = tweet.quote;
  const distinctUrl = hasQuoteCandidate(tweet);
  return Boolean((distinctUrl || quote.text || mediaLinks(quote).length > 0) && (quote.text || mediaLinks(quote).length > 0));
}

function buildDiscordPayloads(tweet, options = {}) {
  try {
    const embedPayloads = buildEmbedDiscordPayloads(tweet, options);
    if (embedPayloads.length) return embedPayloads;
  } catch (error) {
    console.warn("Tweet Discord Share: embed formatting failed, using plain text", error);
  }

  return buildPlainFallbackPayloads(tweet, options);
}

function splitText(text, limit) {
  const value = String(text || "").trim();
  if (!value) return [];
  const chunks = [];
  let remaining = value;

  while (remaining.length > limit) {
    let splitAt = Math.max(
      remaining.lastIndexOf("\n\n", limit),
      remaining.lastIndexOf("\n", limit),
      remaining.lastIndexOf(" ", limit)
    );
    if (splitAt < Math.floor(limit * 0.5)) splitAt = limit;

    chunks.push(remaining.slice(0, splitAt).trim());
    remaining = remaining.slice(splitAt).trim();
  }

  if (remaining) chunks.push(remaining);
  return chunks;
}

  // --- 06-syndication.js ---
async function fetchSyndicationTweet(tweetId) {
  if (!tweetId) return null;
  try {
    return await request("GET", `https://cdn.syndication.twimg.com/tweet-result?id=${tweetId}&lang=en`);
  } catch (error) {
    console.debug("Tweet Discord Share syndication lookup failed", error);
    return null;
  }
}

function bestSyndicationVideoUrl(data) {
  const candidates = [
    ...(data?.video?.variants || []),
    ...(data?.mediaDetails || []).flatMap((media) => media.video_info?.variants || [])
  ];

  return bestPlayableVideoVariantUrl(candidates);
}

function syndicationPosterUrl(data) {
  return data?.video?.poster || data?.mediaDetails?.find((media) => media.media_url_https)?.media_url_https || "";
}

function mediaFromSyndication(data) {
  if (!data) return [];

  const photos = (data.photos || []).map((photo) => ({
    type: "image",
    url: highResolutionTweetImageUrl(photo.url || photo.media_url_https || ""),
    alt: photo.alt_text || ""
  }));
  const details = (data.mediaDetails || []).flatMap((media) => {
    if (media.type === "photo" && media.media_url_https) {
      return [{
        type: "image",
        url: highResolutionTweetImageUrl(media.media_url_https),
        alt: media.ext_alt_text || ""
      }];
    }

    if ((media.type === "video" || media.type === "animated_gif") && media.video_info?.variants) {
      const videoUrl = bestPlayableVideoVariantUrl(media.video_info.variants);
      const posterUrl = media.media_url_https || "";
      return videoUrl || posterUrl ? [{ type: "video", url: videoUrl, posterUrl, alt: media.ext_alt_text || "" }] : [];
    }

    return [];
  });
  const topVideoUrl = bestPlayableVideoVariantUrl(data.video?.variants || []);
  const topVideo = topVideoUrl || data.video?.poster
    ? [{ type: "video", url: topVideoUrl, posterUrl: data.video?.poster || "", alt: "" }]
    : [];

  return uniqueMedia([...photos, ...details, ...topVideo]);
}

function sameTweetImage(left, right) {
  const leftKey = tweetImageMediaKey(left.url);
  return leftKey && leftKey === tweetImageMediaKey(right.url);
}

function sameTweetVideo(left, right) {
  const leftPoster = posterMediaId(left.posterUrl);
  if (leftPoster && leftPoster === posterMediaId(right.posterUrl)) return true;
  const leftUrl = normalizeTweetVideoUrl(left.url || "");
  return leftUrl && leftUrl === normalizeTweetVideoUrl(right.url || "");
}

function mergeTweetMedia(primary = [], fallback = [], options = {}) {
  const media = [...(primary || []), ...(fallback || [])];
  const images = [];
  const videos = [];

  for (const item of media) {
    if (item.type === "image") {
      const normalized = { ...item, url: highResolutionTweetImageUrl(item.url) };
      const existingIndex = images.findIndex((candidate) => sameTweetImage(candidate, normalized));
      if (existingIndex >= 0) {
        const existing = images[existingIndex];
        images[existingIndex] = {
          ...normalized,
          url: existing.url || normalized.url,
          alt: existing.alt || normalized.alt || ""
        };
      } else {
        images.push(normalized);
      }
      continue;
    }

    if (item.type === "video") {
      const normalized = { ...item, url: normalizeTweetVideoUrl(item.url || "") };
      const existingIndex = videos.findIndex((candidate) => sameTweetVideo(candidate, normalized));
      if (existingIndex >= 0) {
        const existing = videos[existingIndex];
        videos[existingIndex] = {
          ...existing,
          ...normalized,
          url: isPlayableTweetVideoUrl(normalized.url) ? normalized.url : existing.url,
          posterUrl: normalized.posterUrl || existing.posterUrl || "",
          alt: normalized.alt || existing.alt || ""
        };
      } else {
        videos.push(normalized);
      }
    }
  }

  const preferredVideoUrl = normalizeTweetVideoUrl(options.cachedVideoUrl || options.videoUrl || "");
  if (preferredVideoUrl) {
    const target = videos.find((item) => !isPlayableTweetVideoUrl(item.url)) || videos[0];
    if (target) {
      target.url = preferredVideoUrl;
      target.posterUrl = target.posterUrl || options.posterUrl || "";
    } else {
      videos.push({ type: "video", url: preferredVideoUrl, posterUrl: options.posterUrl || "", alt: "" });
    }
  }

  return uniqueMedia([...images, ...videos]);
}

function tweetFromSyndication(data, fallback = {}) {
  if (!data) return fallback;

  return {
    ...fallback,
    url: fallback.url || (data.id_str ? `https://x.com/${data.user?.screen_name || "i"}/status/${data.id_str}` : ""),
    author: {
      displayName: data.user?.name || fallback.author?.displayName || "",
      username: data.user?.screen_name || fallback.author?.username || "",
      avatarUrl: highResolutionProfileImageUrl(data.user?.profile_image_url_https || fallback.author?.avatarUrl || "")
    },
    text: data.text || fallback.text || "",
    createdAt: data.created_at || fallback.createdAt || "",
    media: mergeTweetMedia(mediaFromSyndication(data), fallback.media || []),
    quote: fallback.quote
  };
}

function bestCachedTweetForQuote(quote, mainTweetId = "") {
  const quoteText = normalizeTextForMatch(quote.text);
  const quoteUsername = String(quote.author?.username || "").trim();
  const quoteId = quote.url ? tweetIdFromUrl(quote.url) : "";
  if (!quoteText && !quoteUsername && !quoteId) return null;

  if (quoteId && quoteId !== mainTweetId) {
    const byId = TWEET_CACHE.get(quoteId);
    if (byId) return byId;
  }

  if (!quoteUsername) return null;

  for (const [id, cachedTweet] of TWEET_CACHE) {
    if (id === mainTweetId || !/^\d+$/.test(String(id))) continue;
    if (cachedTweet.author?.username !== quoteUsername) continue;

    const cachedText = normalizeTextForMatch(cachedTweet.text);
    if (!quoteText) return cachedTweet;
    if (cachedText === quoteText) return cachedTweet;
    if (quoteText.length >= 24 && cachedText.includes(quoteText)) return cachedTweet;
    if (cachedText.length >= 24 && quoteText.includes(cachedText)) return cachedTweet;
  }

  return null;
}

async function enrichTweetMedia(tweet) {
  const tweetId = tweetIdFromUrl(tweet.url);
  const data = await fetchSyndicationTweet(tweetId);
  const cachedTweet = tweetId ? TWEET_CACHE.get(tweetId) : null;
  tweet = tweetFromSyndication(data, tweet);
  if (cachedTweet) {
    tweet.url = tweet.url || cachedTweet.url || "";
    tweet.author = mergeAuthor(tweet.author, cachedTweet.author);
    tweet.text = tweet.text || cachedTweet.text || "";
    tweet.createdAt = tweet.createdAt || cachedTweet.createdAt || "";
    tweet.media = mergeTweetMedia(tweet.media || [], cachedTweet.media || []);
  }
  const videoUrl = normalizeTweetVideoUrl(bestSyndicationVideoUrl(data));
  const posterUrl = syndicationPosterUrl(data);
  const cachedVideoUrl = bestCachedVideoUrlForTweet(tweet);
  tweet.media = mergeTweetMedia(data ? mediaFromSyndication(data) : [], tweet.media || [], {
    cachedVideoUrl,
    videoUrl,
    posterUrl
  });

  if (hasQuoteCandidate(tweet)) {
    await enrichTweetMedia(tweet.quote);
  }

  if (!hasQuoteTweet(tweet)) {
    tweet.quote = null;
  }

  return tweet;
}

  // --- 07-extract-dom.js ---
function tweetUrlFromArticle(article) {
  const links = [...article.querySelectorAll('a[href*="/status/"]')];
  const statusLinks = links.filter((link) => /\/[^/]+\/status\/\d+/.test(link.getAttribute("href") || ""));
  const pageTweetId = tweetIdFromUrl(location.href);
  const statusLink = statusLinks.find((link) => link.querySelector?.("time"))
    || statusLinks.find((link) => pageTweetId && tweetIdFromUrl(link.href) === pageTweetId)
    || statusLinks[0];
  return statusLink ? normalizeTweetUrl(statusLink.href) : normalizeTweetUrl(location.href);
}

function statusLinksFromArticle(article) {
  const selfHref = article.getAttribute?.("href") || "";
  return [selfHref, ...[...article.querySelectorAll('a[href*="/status/"]')].map((link) => link.href)]
    .filter(Boolean)
    .map((href) => normalizeTweetUrl(href))
    .filter((url, index, all) => /\/status\/\d+/.test(url) && all.indexOf(url) === index);
}

function extractAuthor(article) {
  const userNameBlock = article.querySelector('[data-testid="User-Name"]');
  const avatar = article.querySelector('[data-testid^="UserAvatar-Container"] img, img[src*="profile_images"]');
  const usernameText = [...(userNameBlock || article).querySelectorAll("span")]
    .map((span) => span.textContent?.trim() || "")
    .find((value) => /^@[\w_]+$/.test(value)) || "";
  const profileLink = [...(userNameBlock || article).querySelectorAll('a[href^="/"]')]
    .map((link) => link.getAttribute("href") || "")
    .find((href) => /^\/[^/]+$/.test(href));
  const username = usernameText.slice(1) || profileLink?.slice(1) || "";
  const displayName = text(userNameBlock || article, 'a[href^="/"] div[dir="ltr"] span')
    || [...(userNameBlock || article).querySelectorAll("span")]
      .map((span) => span.textContent?.trim() || "")
      .find((value) => value && value !== usernameText && !/^@/.test(value)) || "";

  return {
    displayName,
    username,
    avatarUrl: highResolutionProfileImageUrl(avatar?.src || "")
  };
}

function normalizeTweetBodyText(value) {
  return String(value || "")
    // X often splits "https://" into its own span; innerText inserts a newline.
    .replace(/(https?:\/\/)\s*\n\s*/gi, "$1")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function readTweetTextNode(node) {
  if (typeof node.cloneNode === "function") {
    const clone = node.cloneNode(true);
    for (const anchor of clone.querySelectorAll("a")) {
      const compact = String(anchor.textContent || "").replace(/\s+/g, "");
      if (/^https?:\/\//i.test(compact) || /^[\w.-]+\.[a-z]{2,}\//i.test(compact)) {
        anchor.replaceWith(compact);
      }
    }
    return normalizeTweetBodyText(clone.innerText || clone.textContent || "");
  }

  return normalizeTweetBodyText(node.innerText || node.textContent || "");
}

function extractText(article, excludedNodes = []) {
  return [...article.querySelectorAll('[data-testid="tweetText"]')]
    .filter((node) => !isInsideExcludedNode(node, excludedNodes))
    .map(readTweetTextNode)
    .filter(Boolean)
    .join("\n\n");
}

function imageNodePixelSize(img) {
  return Math.max(
    Number(img.naturalWidth || 0),
    Number(img.naturalHeight || 0),
    Number(img.width || 0),
    Number(img.height || 0),
    Number(img.clientWidth || 0),
    Number(img.clientHeight || 0)
  );
}

function isLikelyTweetMediaImageNode(img) {
  if (!isTweetImageMediaUrl(img.src) || isTweetVideoThumbnailUrl(img.src)) return false;
  const size = imageNodePixelSize(img);
  return size === 0 || size >= 96;
}

function extractMedia(article, excludedNodes = []) {
  const photoImages = [...article.querySelectorAll('[data-testid="tweetPhoto"] img')]
    .filter((img) => !isInsideExcludedNode(img, excludedNodes))
    .filter((img) => isTweetImageMediaUrl(img.src) && !isTweetVideoThumbnailUrl(img.src));
  const fallbackImages = [...article.querySelectorAll('img[src*="pbs.twimg.com/media/"]')]
    .filter((img) => !isInsideExcludedNode(img, excludedNodes))
    .filter((img) => !img.closest?.('[data-testid="tweetPhoto"]'))
    .filter(isLikelyTweetMediaImageNode);
  const images = [...photoImages, ...fallbackImages]
    .map((img) => ({ type: "image", url: highResolutionTweetImageUrl(img.src), alt: img.alt || "" }));
  const videos = [...article.querySelectorAll("video")]
    .filter((video) => !isInsideExcludedNode(video, excludedNodes))
    .map((video) => ({
      type: "video",
      url: nearestPlayableVideoUrl(video),
      posterUrl: isTweetVideoPosterUrl(video.poster) ? video.poster : "",
      alt: ""
    }));

  return uniqueMedia([...images, ...videos]);
}

function extractTimestamp(article) {
  return article.querySelector("time")?.getAttribute("datetime") || "";
}

function extractQuote(article) {
  const mainUrl = tweetUrlFromArticle(article);
  const statusLinks = statusLinksFromArticle(article);
  const quotedLink = statusLinks.find((href) => href !== mainUrl && tweetIdFromUrl(href) !== tweetIdFromUrl(mainUrl));
  const quotedTweetId = tweetIdFromUrl(quotedLink);

  const quoteCandidates = [
    ...article.querySelectorAll('[role="link"]'),
    ...article.querySelectorAll('[data-testid="card.wrapper"]')
  ];
  const linkedQuoteCandidates = quotedTweetId
    ? quoteCandidates.filter((node) =>
      statusLinksFromArticle(node).some((href) => tweetIdFromUrl(href) === quotedTweetId)
    )
    : [];
  const quotedContainer = linkedQuoteCandidates.find((candidate) =>
    !linkedQuoteCandidates.some((other) =>
      other !== candidate && typeof candidate.contains === "function" && candidate.contains(other)
    )
  ) || quoteCandidates.find((node) => node !== article && node.querySelector('[data-testid="tweetText"]'));

  if (!quotedContainer && !quotedLink) return null;

  const quote = {
    url: quotedLink ? normalizeTweetUrl(quotedLink) : "",
    author: quotedContainer ? extractAuthor(quotedContainer) : { displayName: "", username: "", avatarUrl: "" },
    text: quotedContainer ? extractText(quotedContainer) : "",
    media: quotedContainer ? extractMedia(quotedContainer) : [],
    createdAt: quotedContainer ? extractTimestamp(quotedContainer) : "",
    container: quotedContainer || null
  };

  const cachedQuote = quote.url ? TWEET_CACHE.get(tweetIdFromUrl(quote.url)) : bestCachedTweetForQuote(quote, tweetIdFromUrl(mainUrl));
  if (cachedQuote) {
    quote.url = cachedQuote.url || quote.url;
    quote.author = mergeAuthor(cachedQuote.author, quote.author);
    quote.text = cachedQuote.text || quote.text;
    quote.media = mergeTweetMedia(cachedQuote.media || [], quote.media || []);
    quote.createdAt = cachedQuote.createdAt || quote.createdAt;
  }

  if (DEBUG_QUOTE_EXTRACTION) {
    console.group("Tweet Discord Share quote debug");
    console.log("mainUrl", mainUrl);
    console.log("statusLinks", statusLinks);
    console.log("quotedLink", quotedLink);
    console.log("quotedContainer", quotedContainer);
    console.log("cachedQuote", cachedQuote);
    console.log("tweetCache", Object.fromEntries(TWEET_CACHE));
    console.log("userCache", Object.fromEntries(USER_CACHE));
    console.groupEnd();
  }

  if (!quote.url && !quote.text && quote.media.length === 0) return null;
  if (quote.url && quote.url === mainUrl && !quote.text && quote.media.length === 0) return null;

  return quote;
}

function extractTweet(article) {
  const quote = extractQuote(article);
  const excludedMediaNodes = quote?.container ? [quote.container] : [];

  if (quote) {
    delete quote.container;
  }

  return {
    url: tweetUrlFromArticle(article),
    author: extractAuthor(article),
    text: extractText(article, excludedMediaNodes),
    media: extractMedia(article, excludedMediaNodes),
    createdAt: extractTimestamp(article),
    quote
  };
}

  // --- 08-deliver.js ---
function sanitizeWebhookPayload(payload) {
  const { _messageLabel, ...discordPayload } = payload;
  return discordPayload;
}

function buildWebhookTestPayload() {
  return {
    username: webhookSenderName(),
    avatar_url: webhookSenderAvatarUrl(),
    content: "Tweet Discord Share connected — this channel is ready to receive shares."
  };
}

async function sendWebhookTest(webhookUrl) {
  const url = String(webhookUrl || "").trim();
  if (!isValidWebhookUrl(url)) {
    throw new Error("Enter a valid Discord webhook URL.");
  }
  await request("POST", url, buildWebhookTestPayload());
}

async function shareToDestination(destinationId, tweet, options = {}) {
  const destination = await getDestinationById(destinationId);
  if (!destination?.webhookUrl) {
    throw new Error("That destination is missing a webhook URL.");
  }

  const resolved = await resolveAttachmentsForTweet(tweet, options);
  const attachments = resolved.attachments;
  const fallbackVideoUrls = resolved.skipped
    .map((item) => item.sourceUrl)
    .filter((url) => isPlayableTweetVideoUrl(url));
  const payloads = buildDiscordPayloads(tweet, {
    ...options,
    attachMedia: attachments.length > 0,
    attachmentUrls: resolved.urls,
    fallbackVideoUrls
  });

  if (resolved.skipped.length > 0 && attachments.length === 0) {
    showToast("Media could not upload; sent available fallback content.", "info");
  }

  for (let index = 0; index < payloads.length; index += 1) {
    const payload = sanitizeWebhookPayload(payloads[index]);
    try {
      if (index === 0 && attachments.length > 0) {
        await requestMultipart(
          destination.webhookUrl,
          payload,
          attachments.map((attachment, fileIndex) => ({
            name: `files[${fileIndex}]`,
            filename: attachment.filename,
            bytes: attachment.bytes,
            contentType: attachment.contentType
          }))
        );
      } else {
        await request("POST", destination.webhookUrl, payload);
      }
    } catch (error) {
      if (index === 0) throw error;
      throw new Error(
        `Sent ${index} of ${payloads.length} Discord messages before delivery failed: ${error.message}`,
        { cause: error }
      );
    }
    if (index < payloads.length - 1) {
      await delay(WEBHOOK_SEND_DELAY_MS);
    }
  }

  if (attachments.length > 0 && resolved.skipped.length > 0) {
    const skippedSummary = summarizeSkippedMedia(resolved.skipped);
    showToast(`Uploaded ${attachments.length} file${attachments.length === 1 ? "" : "s"}; ${skippedSummary}.`, "info");
  }
}

